class Solution:
    def numberOfPowerfulInt(self, start, finish, limit, s):
        # Independent digit-DP (position + tight-bound recursion) rather than
        # the closed-form prefix-count arithmetic used by the main solution.
        from functools import lru_cache

        def count_upto(x):
            if x <= 0:
                return 0
            xs = str(x)
            n = len(xs)
            sl = len(s)
            if n < sl:
                return 0
            suffix_start = n - sl

            @lru_cache(maxsize=None)
            def rec(pos, tight):
                if pos == n:
                    return 1
                hi = int(xs[pos]) if tight else 9
                total = 0
                for d in range(0, min(hi, limit) + 1):
                    if pos >= suffix_start:
                        req = int(s[pos - suffix_start])
                        if d != req:
                            continue
                    total += rec(pos + 1, tight and d == hi)
                return total

            result = rec(0, True)
            rec.cache_clear()
            return result

        return count_upto(finish) - count_upto(start - 1)

