class Solution:
    def numberOfPowerfulInt(self, start, finish, limit, s):
        def count_le(bound_str):
            res = 0
            n = len(bound_str)
            for i, ch in enumerate(bound_str):
                d = int(ch)
                if d > limit:
                    res += (limit + 1) ** (n - i)
                    return res
                res += d * (limit + 1) ** (n - i - 1)
            return res + 1

        def count_upto(x):
            if x <= 0 or x < int(s):
                return 0
            xs = str(x)
            n = len(xs)
            sl = len(s)
            if n < sl:
                return 0
            prefix_len = n - sl
            if prefix_len == 0:
                return 1 if int(s) <= x else 0
            bound_prefix = xs[:prefix_len]
            bound_qualifies = all(int(ch) <= limit for ch in bound_prefix)
            cnt_le_including = count_le(bound_prefix)
            cnt_less = cnt_le_including - (1 if bound_qualifies else 0)
            suffix_of_x = int(xs[prefix_len:])
            total = cnt_less
            if bound_qualifies and int(s) <= suffix_of_x:
                total += 1
            return total

        return count_upto(finish) - count_upto(start - 1)

