function countLe(boundStr, limit) {
    let res = 0n;
    const n = boundStr.length;
    const L = BigInt(limit + 1);
    for (let i = 0; i < n; i++) {
        const d = boundStr.charCodeAt(i) - 48;
        if (d > limit) {
            res += L ** BigInt(n - i);
            return res;
        }
        res += BigInt(d) * (L ** BigInt(n - i - 1));
    }
    return res + 1n;
}

function countUpto(x, limit, s) {
    if (x <= 0) return 0n;
    const sNum = BigInt(s);
    if (BigInt(x) < sNum) return 0n;
    const xs = String(x);
    const n = xs.length;
    const sl = s.length;
    if (n < sl) return 0n;
    const prefixLen = n - sl;
    if (prefixLen === 0) {
        return sNum <= BigInt(x) ? 1n : 0n;
    }
    const boundPrefix = xs.slice(0, prefixLen);
    let boundQualifies = true;
    for (const ch of boundPrefix) {
        if (ch.charCodeAt(0) - 48 > limit) { boundQualifies = false; break; }
    }
    const cntLeIncluding = countLe(boundPrefix, limit);
    let cntLess = cntLeIncluding - (boundQualifies ? 1n : 0n);
    const suffixOfX = BigInt(xs.slice(prefixLen));
    let total = cntLess;
    if (boundQualifies && sNum <= suffixOfX) total += 1n;
    return total;
}

var numberOfPowerfulInt = function(start, finish, limit, s) {
    const result = countUpto(finish, limit, s) - countUpto(start - 1, limit, s);
    return Number(result);
};
